# handoff_document.py — generates structured handoff doc and posts to Slack
from dataclasses import dataclass, field
from datetime import datetime, timezone
from typing import Optional
import os, requests

SLACK_WEBHOOK = os.environ['SLACK_ONCALL_WEBHOOK']

@dataclass
class SLOBudget:
    slo_id: str
    remaining_fraction: float
    freeze_status: str  # 'normal', 'soft', 'hard', 'exhausted'

@dataclass
class OpenIncident:
    ticket_id: str
    summary: str
    priority: str  # 'P1' or 'P2'
    owner: str
    status: str
    expected_resolution: Optional[str] = None

@dataclass
class ScheduledDeploy:
    description: str
    deploy_type: str    # 'feature', 'hotfix', 'model-update'
    scheduled_date: str
    contact: str
    risk_level: str     # 'low', 'medium', 'high'

@dataclass
class HandoffDocument:
    outgoing_oncall: str
    incoming_oncall: str
    handoff_time: datetime = field(default_factory=lambda: datetime.now(timezone.utc))
    budget_snapshots: list[SLOBudget] = field(default_factory=list)
    open_incidents: list[OpenIncident] = field(default_factory=list)
    scheduled_deploys: list[ScheduledDeploy] = field(default_factory=list)
    known_fragility: list[str] = field(default_factory=list)
    runbook_updates: list[str] = field(default_factory=list)

    def has_blocking_conditions(self) -> list[str]:
        blocks = []
        active_incidents = [
            i for i in self.open_incidents
            if i.priority == 'P1'
        ]
        if active_incidents:
            blocks.append(
                f'{len(active_incidents)} active P1 incident(s) — '
                'synchronous handoff required'
            )
        low_budget = [
            b for b in self.budget_snapshots
            if b.remaining_fraction < 0.20
        ]
        if low_budget:
            names = ', '.join(b.slo_id for b in low_budget)
            blocks.append(
                f'Budget below 20% for: {names} — '
                'incoming on-call must acknowledge freeze watch'
            )
        return blocks

    def to_slack_message(self) -> str:
        lines = [
            f'*On-Call Handoff — {self.handoff_time.strftime("%Y-%m-%d %H:%M UTC")}*',
            f':outbox_tray: Outgoing: {self.outgoing_oncall}',
            f':inbox_tray: Incoming: {self.incoming_oncall}',
            '',
        ]
        lines.append('*1. Budget Snapshot*')
        for b in self.budget_snapshots:
            emoji = ':white_check_mark:' if b.remaining_fraction > 0.20 else ':warning:'
            lines.append(
                f'  {emoji} {b.slo_id}: {b.remaining_fraction:.0%} remaining '
                f'({b.freeze_status})'
            )
        lines.append('')

        if self.open_incidents:
            lines.append('*2. Open Incidents* :rotating_light:')
            for i in self.open_incidents:
                lines.append(
                    f'  • [{i.priority}] {i.ticket_id}: {i.summary} '
                    f'(owner: {i.owner}, status: {i.status})'
                )
        else:
            lines.append('*2. Open Incidents*: None :white_check_mark:')
        lines.append('')

        if self.known_fragility:
            lines.append('*3. Known Fragility*')
            for f in self.known_fragility:
                lines.append(f'  • {f}')

        blocks = self.has_blocking_conditions()
        if blocks:
            lines += ['', ':no_entry: *HANDOFF BLOCKED* — resolve before pager transfer:']
            for b in blocks:
                lines.append(f'  • {b}')

        return '\n'.join(lines)

def post_handoff(doc: HandoffDocument) -> None:
    message = doc.to_slack_message()
    requests.post(SLACK_WEBHOOK, json={'text': message}, timeout=5)

# runbook_lint.py — checks that all deployed alerts have a runbook
import os
import re
import sys
from datetime import date, timedelta
from pathlib import Path
import yaml

RUNBOOK_DIR = Path('runbooks')
ALERT_RULES_DIR = Path('monitoring/alerts')

def get_alert_names_from_rules() -> set[str]:
    names = set()
    for rules_file in ALERT_RULES_DIR.glob('*.yaml'):
        with rules_file.open() as f:
            data = yaml.safe_load(f)
        for group in data.get('groups', []):
            for rule in group.get('rules', []):
                if 'alert' in rule:
                    names.add(rule['alert'])
    return names

def get_runbook_status() -> dict[str, dict]:
    status = {}
    for rb_file in RUNBOOK_DIR.glob('*.md'):
        name = rb_file.stem
        content = rb_file.read_text()
        # extract 'Last reviewed' date
        match = re.search(r'Last reviewed.*?(\d{4}-\d{2}-\d{2})', content)
        last_reviewed = date.fromisoformat(match.group(1)) if match else None
        age_days = (date.today() - last_reviewed).days if last_reviewed else 9999
        if age_days <= 90:
            health = 'current'
        elif age_days <= 180:
            health = 'stale'
        else:
            health = 'expired'
        status[name] = {
            'file': str(rb_file),
            'last_reviewed': str(last_reviewed),
            'age_days': age_days,
            'health': health,
        }
    return status

def lint_runbooks() -> int:
    alert_names = get_alert_names_from_rules()
    runbook_status = get_runbook_status()
    failures = 0

    for alert in sorted(alert_names):
        rb = runbook_status.get(alert)
        if rb is None:
            print(f'MISSING   {alert}: no runbook found in {RUNBOOK_DIR}')
            failures += 1
        elif rb['health'] == 'expired':
            print(
                f'EXPIRED   {alert}: last reviewed {rb["last_reviewed"]} '
                f'({rb["age_days"]} days ago)'
            )
            failures += 1
        elif rb['health'] == 'stale':
            print(
                f'STALE     {alert}: last reviewed {rb["last_reviewed"]} '
                f'({rb["age_days"]} days ago) — review recommended'
            )
        else:
            print(f'OK        {alert}')

    return failures

if __name__ == '__main__':
    failures = lint_runbooks()
    if failures:
        print(f'\n{failures} runbook failure(s). Fix before deploying new alert rules.')
        sys.exit(1)
    print('\nAll runbooks current.')
